'use client';

import { zodResolver } from '@hookform/resolvers/zod';
import { useForm } from 'react-hook-form';
import { z } from 'zod';
import { Button } from '@/components/ui/button';
import {
  Form,
  FormControl,
  FormDescription,
  FormField,
  FormItem,
  FormLabel,
  FormMessage,
} from '@/components/ui/form';
import { Input } from '@/components/ui/input';
import { Checkbox } from '@/components/ui/checkbox';
import { Calendar } from '@/components/ui/calendar';
import {
  Popover,
  PopoverContent,
  PopoverTrigger,
} from '@/components/ui/popover';
import { CalendarIcon, Loader2 } from 'lucide-react';
import { cn } from '@/lib/utils';
import { format, add } from 'date-fns';
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '@/components/ui/card';
import {
    boxHireServices,
    services,
    protectionAddOns,
    tvProtectionAddOns,
    protectionBundles,
} from '@/lib/data';
import { useState } from 'react';
import { useToast } from '@/hooks/use-toast';
import { recommendAdditionalEquipment } from '@/ai/flows/recommend-additional-equipment';
import { Service, ProtectionBundle } from '@/lib/types';


const allItems = [
    ...boxHireServices,
    ...services,
    ...protectionAddOns,
    ...tvProtectionAddOns,
    ...protectionBundles,
];

const formSchema = z.object({
  name: z.string().min(2, { message: 'Name must be at least 2 characters.' }),
  email: z.string().email({ message: 'Please enter a valid email.' }),
  items: z.array(z.string()).refine((value) => value.some((item) => item), {
    message: 'You have to select at least one item.',
  }),
  rentalStartDate: z.date({
    required_error: 'A start date is required.',
  }),
  rentalEndDate: z.date({
    required_error: 'An end date is required.',
  }),
});

function ItemCheckboxList({ form, title, items }: { form: any, title: string, items: (Service | ProtectionBundle)[] }) {
    const formatPrice = (item: Service | ProtectionBundle) => {
        let priceString = '';
        if ('price' in item && item.price) {
            priceString = item.price;
            if ('unit' in item && item.unit) {
                priceString += `/${item.unit}`;
            }
        } else {
            const hirePrice = 'hirePrice' in item ? item.hirePrice : null;
            const purchasePrice = 'purchasePrice' in item ? item.purchasePrice : null;

            if (hirePrice && purchasePrice) {
                priceString = `Hire: ${hirePrice} / Buy: ${purchasePrice}`;
            } else if (hirePrice) {
                priceString = `Hire: ${hirePrice}`;
            } else if (purchasePrice) {
                priceString = `Buy: ${purchasePrice}`;
            }
        }
        return priceString ? ` - ${priceString}` : '';
    }

    return (
        <div className="space-y-4">
            <h4 className="text-md font-medium">{title}</h4>
            {items.map((item) => (
                <FormField
                    key={item.id}
                    control={form.control}
                    name="items"
                    render={({ field }) => {
                    return (
                        <FormItem
                        key={item.id}
                        className="flex flex-row items-start space-x-3 space-y-0"
                        >
                        <FormControl>
                            <Checkbox
                            checked={field.value?.includes(item.id)}
                            onCheckedChange={(checked) => {
                                return checked
                                ? field.onChange([...(field.value || []), item.id])
                                : field.onChange(
                                    field.value?.filter(
                                        (value: string) => value !== item.id
                                    )
                                    );
                            }}
                            />
                        </FormControl>
                        <FormLabel className="font-normal">
                            {item.name}
                            <span className="text-muted-foreground">{formatPrice(item)}</span>
                        </FormLabel>
                        </FormItem>
                    );
                    }}
                />
            ))}
        </div>
    )
}

export function QuoteForm() {
    const [isLoading, setIsLoading] = useState(false);
    const { toast } = useToast();
    const [recommendation, setRecommendation] = useState<{ recommendedEquipment: string, reasoning: string } | null>(null);

  const form = useForm<z.infer<typeof formSchema>>({
    resolver: zodResolver(formSchema),
    defaultValues: {
      name: '',
      email: '',
      items: [],
    },
  });

  async function onSubmit(values: z.infer<typeof formSchema>) {
    setIsLoading(true);
    setRecommendation(null);
    try {
        const selectedItems = values.items.map(id => allItems.find(item => item.id === id)?.name || 'Unknown Item').join(', ');
        
        const aiRecommendation = await recommendAdditionalEquipment({
            equipmentList: selectedItems
        });

        if (aiRecommendation.recommendedEquipment) {
            setRecommendation(aiRecommendation);
        }

      toast({
        title: 'Quote Request Submitted!',
        description: 'We have received your request and will get back to you shortly.',
      });
      // Here you would typically send the data to your backend
      console.log(values);
      form.reset();
    } catch (error) {
      console.error('Failed to submit quote or get recommendation', error);
      toast({
        variant: 'destructive',
        title: 'Submission Failed',
        description: 'There was a problem submitting your quote request. Please try again.',
      });
    } finally {
        setIsLoading(false);
    }
  }

  const handleStartDateSelect = (date: Date | undefined) => {
    form.setValue('rentalStartDate', date as Date);
    if (date) {
      const twoWeeksLater = add(date, { weeks: 2 });
      form.setValue('rentalEndDate', twoWeeksLater);
    }
  };

  return (
    <Card>
      <CardHeader>
        <CardTitle className="text-3xl font-headline">Request a Quote</CardTitle>
        <CardDescription>
          Fill out the form below to get a personalized quote for your project.
        </CardDescription>
      </CardHeader>
      <CardContent>
        <Form {...form}>
          <form onSubmit={form.handleSubmit(onSubmit)} className="space-y-8">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                <FormField
                control={form.control}
                name="name"
                render={({ field }) => (
                    <FormItem>
                    <FormLabel>Full Name</FormLabel>
                    <FormControl>
                        <Input placeholder="John Doe" {...field} />
                    </FormControl>
                    <FormMessage />
                    </FormItem>
                )}
                />
                <FormField
                control={form.control}
                name="email"
                render={({ field }) => (
                    <FormItem>
                    <FormLabel>Email Address</FormLabel>
                    <FormControl>
                        <Input placeholder="you@example.com" {...field} />
                    </FormControl>
                    <FormMessage />
                    </FormItem>
                )}
                />
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                <FormField
                control={form.control}
                name="rentalStartDate"
                render={({ field }) => (
                    <FormItem className="flex flex-col">
                    <FormLabel>Rental Start Date</FormLabel>
                    <Popover>
                        <PopoverTrigger asChild>
                        <FormControl>
                            <Button
                            variant={'outline'}
                            className={cn(
                                'w-full pl-3 text-left font-normal',
                                !field.value && 'text-muted-foreground'
                            )}
                            >
                            {field.value ? (
                                format(field.value, 'PPP')
                            ) : (
                                <span>Pick a date</span>
                            )}
                            <CalendarIcon className="ml-auto h-4 w-4 opacity-50" />
                            </Button>
                        </FormControl>
                        </PopoverTrigger>
                        <PopoverContent className="w-auto p-0" align="start">
                        <Calendar
                            mode="single"
                            selected={field.value}
                            onSelect={handleStartDateSelect}
                            disabled={(date) =>
                                date < new Date(new Date().setHours(0, 0, 0, 0))
                            }
                            initialFocus
                        />
                        </PopoverContent>
                    </Popover>
                    <FormMessage />
                    </FormItem>
                )}
                />
                <FormField
                control={form.control}
                name="rentalEndDate"
                render={({ field }) => (
                    <FormItem className="flex flex-col">
                    <FormLabel>Rental End Date</FormLabel>
                    <Popover>
                        <PopoverTrigger asChild>
                        <FormControl>
                            <Button
                            variant={'outline'}
                            className={cn(
                                'w-full pl-3 text-left font-normal',
                                !field.value && 'text-muted-foreground'
                            )}
                            >
                            {field.value ? (
                                format(field.value, 'PPP')
                            ) : (
                                <span>Pick a date</span>
                            )}
                            <CalendarIcon className="ml-auto h-4 w-4 opacity-50" />
                            </Button>
                        </FormControl>
                        </PopoverTrigger>
                        <PopoverContent className="w-auto p-0" align="start">
                        <Calendar
                            mode="single"
                            selected={field.value}
                            onSelect={field.onChange}
                            disabled={(date) =>
                                date < (form.getValues('rentalStartDate') || new Date(new Date().setHours(0, 0, 0, 0)))
                            }
                            initialFocus
                        />
                        </PopoverContent>
                    </Popover>
                    <FormMessage />
                    </FormItem>
                )}
                />
            </div>
            
            <FormField
                control={form.control}
                name="items"
                render={() => (
                    <FormItem>
                        <div className="mb-4">
                            <FormLabel className="text-base">Select Items</FormLabel>
                            <FormDescription>
                                Choose the items you&apos;d like to include in your quote.
                            </FormDescription>
                        </div>
                        <div className="space-y-8">
                            <div>
                                <h3 className="text-lg font-semibold mb-4">Box Hire</h3>
                                <ItemCheckboxList form={form} title="" items={boxHireServices} />
                            </div>
                            <div>
                                <h3 className="text-lg font-semibold mb-4">Optional Add-Ons</h3>
                                <ItemCheckboxList form={form} title="" items={services} />
                            </div>
                            <div className="space-y-6">
                                <h3 className="text-lg font-semibold">Protection Add-Ons</h3>
                                <ItemCheckboxList form={form} title="Mattress Protection" items={protectionAddOns} />
                                <ItemCheckboxList form={form} title="TV Protection" items={tvProtectionAddOns} />
                                <ItemCheckboxList form={form} title="Protection Bundles" items={protectionBundles} />
                            </div>
                        </div>
                        <FormMessage />
                    </FormItem>
                )}
            />

            {recommendation && (
              <Card className="bg-blue-50 border-blue-200 dark:bg-blue-900/30">
                <CardHeader>
                  <CardTitle className="text-xl font-headline text-blue-800 dark:text-blue-300">AI Recommendation</CardTitle>
                </CardHeader>
                <CardContent className="space-y-2">
                  <p>Based on your project, we also recommend: <span className="font-semibold">{recommendation.recommendedEquipment}</span></p>
                  <p className="text-sm text-muted-foreground">{recommendation.reasoning}</p>
                </CardContent>
              </Card>
            )}

            <Button type="submit" disabled={isLoading}>
                {isLoading && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
              Submit Quote Request
            </Button>
          </form>
        </Form>
      </CardContent>
    </Card>
  );
}
